   295→<body>
   296→    <div class="game-container">
   297→        <div class="game-header">
   298→            <h1>♚ Xadrez Fácil ♛</h1>
   299→        </div>
   300→
   301→        <div class="game-info">
   302→            <div class="turn-indicator" id="turnIndicator">Vez das Brancas</div>
   303→            <div class="status-message" id="statusMessage"></div>
   304→        </div>
   305→
   306→        <div class="captured-pieces">
   307→            <div class="captured-side" id="capturedWhite"></div>
   308→            <div class="captured-side" id="capturedBlack"></div>
   309→        </div>
   310→
   311→        <div class="chess-board" id="chessBoard"></div>
   312→
   313→        <div class="controls">
   314→            <button class="btn btn-primary" onclick="resetGame()">Novo Jogo</button>
   315→            <button class="btn btn-secondary" onclick="undoMove()">Desfazer</button>
   316→        </div>
   317→
   318→        <div class="move-history">
   319→            <h3>Histórico de Jogadas</h3>
   320→            <div class="moves-list" id="movesList"></div>
   321→        </div>
   322→    </div>
   323→
   324→    <script>
   325→        // Chess pieces Unicode
   326→        const PIECES = {
   327→            white: { king: '♔', queen: '♕', rook: '♖', bishop: '♗', knight: '♘', pawn: '♙' },
   328→            black: { king: '♚', queen: '♛', rook: '♜', bishop: '♝', knight: '♞', pawn: '♟' }
   329→        };
   330→
   331→        // Initial board setup
   332→        const INITIAL_BOARD = [
   333→            ['r', 'n', 'b', 'q', 'k', 'b', 'n', 'r'],
   334→            ['p', 'p', 'p', 'p', 'p', 'p', 'p', 'p'],
   335→            ['', '', '', '', '', '', '', ''],
   336→            ['', '', '', '', '', '', '', ''],
   337→            ['', '', '', '', '', '', '', ''],
   338→            ['', '', '', '', '', '', '', ''],
   339→            ['P', 'P', 'P', 'P', 'P', 'P', 'P', 'P'],
   340→            ['R', 'N', 'B', 'Q', 'K', 'B', 'N', 'R']
   341→        ];
   342→
   343→        let board = [];
   344→        let selectedSquare = null;
   345→        let currentTurn = 'white';
   346→        let moveHistory = [];
   347→        let capturedPieces = { white: [], black: [] };
   348→        let lastMove = null;
   349→        let castlingRights = {
   350→            white: { kingSide: true, queenSide: true },
   351→            black: { kingSide: true, queenSide: true }
   352→        };
   353→        let enPassantTarget = null;
   354→
   355→        function initGame() {
   356→            board = JSON.parse(JSON.stringify(INITIAL_BOARD));
   357→            selectedSquare = null;
   358→            currentTurn = 'white';
   359→            moveHistory = [];
   360→            capturedPieces = { white: [], black: [] };
   361→            lastMove = null;
   362→            castlingRights = {
   363→                white: { kingSide: true, queenSide: true },
   364→                black: { kingSide: true, queenSide: true }
   365→            };
   366→            enPassantTarget = null;
   367→            renderBoard();
   368→            updateGameInfo();
   369→        }
   370→
   371→        function renderBoard() {
   372→            const boardElement = document.getElementById('chessBoard');
   373→            boardElement.innerHTML = '';
   374→
   375→            for (let row = 0; row < 8; row++) {
   376→                for (let col = 0; col < 8; col++) {
   377→                    const square = document.createElement('div');
   378→                    const isLight = (row + col) % 2 === 0;
   379→                    square.className = `square ${isLight ? 'light' : 'dark'}`;
   380→                    square.dataset.row = row;
   381→                    square.dataset.col = col;
   382→
   383→                    const piece = board[row][col];
   384→                    if (piece) {
   385→                        const pieceColor = piece === piece.toUpperCase() ? 'white' : 'black';
   386→                        const pieceType = getPieceType(piece);
   387→                        const pieceElement = document.createElement('span');
   388→                        pieceElement.className = `piece ${pieceColor}`;
   389→                        pieceElement.textContent = PIECES[pieceColor][pieceType];
   390→                        square.appendChild(pieceElement);
   391→                    }
   392→
   393→                    // Highlight last move
   394→                    if (lastMove && ((lastMove.from.row === row && lastMove.from.col === col) ||
   395→                        (lastMove.to.row === row && lastMove.to.col === col))) {
   396→                        square.classList.add('last-move');
   397→                    }
   398→
   399→                    // Highlight selected square
   400→                    if (selectedSquare && selectedSquare.row === row && selectedSquare.col === col) {
   401→                        square.classList.add('selected');
   402→                    }
   403→
   404→                    // Highlight valid moves
   405→                    if (selectedSquare) {
   406→                        const moves = getValidMoves(selectedSquare.row, selectedSquare.col);
   407→                        if (moves.some(m => m.row === row && m.col === col)) {
   408→                            if (piece) {
   409→                                square.classList.add('capture-move');
   410→                            } else {
   411→                                square.classList.add('valid-move');
   412→                            }
   413→                        }
   414→                    }
   415→
   416→                    // Highlight king in check
   417→                    if (piece && piece.toLowerCase() === 'k') {
   418→                        const pieceColor = piece === piece.toUpperCase() ? 'white' : 'black';
   419→                        if (isInCheck(pieceColor)) {
   420→                            square.classList.add('in-check');
   421→                        }
   422→                    }
   423→
   424→                    square.addEventListener('click', () => handleSquareClick(row, col));
   425→                    boardElement.appendChild(square);
   426→                }
   427→            }
   428→        }
   429→
   430→        function getPieceType(piece) {
   431→            const pieceLower = piece.toLowerCase();
   432→            const types = {
   433→                'k': 'king', 'q': 'queen', 'r': 'rook',
   434→                'b': 'bishop', 'n': 'knight', 'p': 'pawn'
   435→            };
   436→            return types[pieceLower];
   437→        }
   438→
   439→        function handleSquareClick(row, col) {
   440→            const piece = board[row][col];
   441→            const pieceColor = piece ? (piece === piece.toUpperCase() ? 'white' : 'black') : null;
   442→
   443→            if (selectedSquare) {
   444→                const moves = getValidMoves(selectedSquare.row, selectedSquare.col);
   445→                const validMove = moves.find(m => m.row === row && m.col === col);
   446→
   447→                if (validMove) {
   448→                    makeMove(selectedSquare.row, selectedSquare.col, row, col);
   449→                    selectedSquare = null;
   450→                } else if (pieceColor === currentTurn) {
   451→                    selectedSquare = { row, col };
   452→                } else {
   453→                    selectedSquare = null;
   454→                }
   455→            } else if (pieceColor === currentTurn) {
   456→                selectedSquare = { row, col };
   457→            }
   458→
   459→            renderBoard();
   460→        }
   461→
   462→        function makeMove(fromRow, fromCol, toRow, toCol) {
   463→            const piece = board[fromRow][fromCol];
   464→            const capturedPiece = board[toRow][toCol];
   465→            const pieceColor = piece === piece.toUpperCase() ? 'white' : 'black';
   466→
   467→            // Save move for history
   468→            const move = {
   469→                from: { row: fromRow, col: fromCol },
   470→                to: { row: toRow, col: toCol },
   471→                piece: piece,
   472→                captured: capturedPiece,
   473→                castling: null,
   474→                enPassant: false,
   475→                promotion: false
   476→            };
   477→
   478→            // Handle en passant capture
   479→            if (piece.toLowerCase() === 'p' && enPassantTarget &&
   480→                toRow === enPassantTarget.row && toCol === enPassantTarget.col) {
   481→                const capturedPawnRow = pieceColor === 'white' ? toRow + 1 : toRow - 1;
   482→                const capturedPawn = board[capturedPawnRow][toCol];
   483→                capturedPieces[pieceColor].push(capturedPawn);
   484→                board[capturedPawnRow][toCol] = '';
   485→                move.enPassant = true;
   486→                move.captured = capturedPawn;
   487→            }
   488→
   489→            // Handle castling
   490→            if (piece.toLowerCase() === 'k' && Math.abs(fromCol - toCol) === 2) {
   491→                const isKingSide = toCol > fromCol;
   492→                const rookFromCol = isKingSide ? 7 : 0;
   493→                const rookToCol = isKingSide ? 5 : 3;
   494→                board[toRow][rookToCol] = board[toRow][rookFromCol];
   495→                board[toRow][rookFromCol] = '';
   496→                move.castling = isKingSide ? 'kingSide' : 'queenSide';
   497→            }
   498→
   499→            // Update castling rights
   500→            if (piece.toLowerCase() === 'k') {
   501→                castlingRights[pieceColor].kingSide = false;
   502→                castlingRights[pieceColor].queenSide = false;
   503→            }
   504→            if (piece.toLowerCase() === 'r') {
   505→                if (fromCol === 0) castlingRights[pieceColor].queenSide = false;
   506→                if (fromCol === 7) castlingRights[pieceColor].kingSide = false;
   507→            }
   508→
   509→            // Set en passant target
   510→            enPassantTarget = null;
   511→            if (piece.toLowerCase() === 'p' && Math.abs(fromRow - toRow) === 2) {
   512→                enPassantTarget = {
   513→                    row: (fromRow + toRow) / 2,
   514→                    col: fromCol
   515→                };
   516→            }
   517→
   518→            // Handle promotion
   519→            if (piece.toLowerCase() === 'p' && (toRow === 0 || toRow === 7)) {
   520→                board[toRow][toCol] = pieceColor === 'white' ? 'Q' : 'q';
   521→                move.promotion = true;
   522→            } else {
   523→                board[toRow][toCol] = piece;
   524→            }
   525→
   526→            board[fromRow][fromCol] = '';
   527→
   528→            if (capturedPiece) {
   529→                capturedPieces[pieceColor].push(capturedPiece);
   530→            }
   531→
   532→            moveHistory.push(move);
   533→            lastMove = { from: { row: fromRow, col: fromCol }, to: { row: toRow, col: toCol } };
   534→
   535→            currentTurn = currentTurn === 'white' ? 'black' : 'white';
   536→            updateGameInfo();
   537→        }
   538→
   539→        function getValidMoves(row, col) {
   540→            const piece = board[row][col];
   541→            if (!piece) return [];
   542→
   543→            const pieceColor = piece === piece.toUpperCase() ? 'white' : 'black';
   544→            const pieceType = piece.toLowerCase();
   545→            let moves = [];
   546→
   547→            switch (pieceType) {
   548→                case 'p':
   549→                    moves = getPawnMoves(row, col, pieceColor);
   550→                    break;
   551→                case 'r':
   552→                    moves = getRookMoves(row, col, pieceColor);
   553→                    break;
   554→                case 'n':
   555→                    moves = getKnightMoves(row, col, pieceColor);
   556→                    break;
   557→                case 'b':
   558→                    moves = getBishopMoves(row, col, pieceColor);
   559→                    break;
   560→                case 'q':
   561→                    moves = getQueenMoves(row, col, pieceColor);
   562→                    break;
   563→                case 'k':
   564→                    moves = getKingMoves(row, col, pieceColor);
   565→                    break;
   566→            }
   567→
   568→            // Filter out moves that would leave king in check
   569→            return moves.filter(move => !wouldBeInCheck(row, col, move.row, move.col, pieceColor));
   570→        }
   571→
   572→        function getPawnMoves(row, col, color) {
   573→            const moves = [];
   574→            const direction = color === 'white' ? -1 : 1;
   575→            const startRow = color === 'white' ? 6 : 1;
   576→
   577→            // Forward move
   578→            if (isInBounds(row + direction, col) && !board[row + direction][col]) {
   579→                moves.push({ row: row + direction, col: col });
   580→
   581→                // Double move from start
   582→                if (row === startRow && !board[row + 2 * direction][col]) {
   583→                    moves.push({ row: row + 2 * direction, col: col });
   584→                }
   585→            }
   586→
   587→            // Captures
   588→            for (const colOffset of [-1, 1]) {
   589→                const newRow = row + direction;
   590→                const newCol = col + colOffset;
   591→
   592→                if (isInBounds(newRow, newCol)) {
   593→                    const targetPiece = board[newRow][newCol];
   594→                    const targetColor = targetPiece ?
   595→                        (targetPiece === targetPiece.toUpperCase() ? 'white' : 'black') : null;
   596→
   597→                    if (targetPiece && targetColor !== color) {
   598→                        moves.push({ row: newRow, col: newCol });
   599→                    }
   600→
   601→                    // En passant
   602→                    if (enPassantTarget && enPassantTarget.row === newRow &&
   603→                        enPassantTarget.col === newCol) {
   604→                        moves.push({ row: newRow, col: newCol });
   605→                    }
   606→                }
   607→            }
   608→
   609→            return moves;
   610→        }
   611→
   612→        function getRookMoves(row, col, color) {
   613→            return getSlidingMoves(row, col, color, [[0, 1], [0, -1], [1, 0], [-1, 0]]);
   614→        }
   615→
   616→        function getBishopMoves(row, col, color) {
   617→            return getSlidingMoves(row, col, color, [[1, 1], [1, -1], [-1, 1], [-1, -1]]);
   618→        }
   619→
   620→        function getQueenMoves(row, col, color) {
   621→            return getSlidingMoves(row, col, color, [
   622→                [0, 1], [0, -1], [1, 0], [-1, 0],
   623→                [1, 1], [1, -1], [-1, 1], [-1, -1]
   624→            ]);
   625→        }
   626→
   627→        function getSlidingMoves(row, col, color, directions) {
   628→            const moves = [];
   629→
   630→            for (const [rowDir, colDir] of directions) {
   631→                let newRow = row + rowDir;
   632→                let newCol = col + colDir;
   633→
   634→                while (isInBounds(newRow, newCol)) {
   635→                    const targetPiece = board[newRow][newCol];
   636→
   637→                    if (!targetPiece) {
   638→                        moves.push({ row: newRow, col: newCol });
   639→                    } else {
   640→                        const targetColor = targetPiece === targetPiece.toUpperCase() ? 'white' : 'black';
   641→                        if (targetColor !== color) {
   642→                            moves.push({ row: newRow, col: newCol });
   643→                        }
   644→                        break;
   645→                    }
   646→
   647→                    newRow += rowDir;
   648→                    newCol += colDir;
   649→                }
   650→            }
   651→
   652→            return moves;
   653→        }
   654→
   655→        function getKnightMoves(row, col, color) {
   656→            const moves = [];
   657→            const offsets = [
   658→                [-2, -1], [-2, 1], [-1, -2], [-1, 2],
   659→                [1, -2], [1, 2], [2, -1], [2, 1]
   660→            ];
   661→
   662→            for (const [rowOffset, colOffset] of offsets) {
   663→                const newRow = row + rowOffset;
   664→                const newCol = col + colOffset;
   665→
   666→                if (isInBounds(newRow, newCol)) {
   667→                    const targetPiece = board[newRow][newCol];
