   682→        function getKingMoves(row, col, color) {
   683→            const moves = [];
   684→            const offsets = [
   685→                [-1, -1], [-1, 0], [-1, 1],
   686→                [0, -1],          [0, 1],
   687→                [1, -1],  [1, 0], [1, 1]
   688→            ];
   689→
   690→            for (const [rowOffset, colOffset] of offsets) {
   691→                const newRow = row + rowOffset;
   692→                const newCol = col + colOffset;
   693→
   694→                if (isInBounds(newRow, newCol)) {
   695→                    const targetPiece = board[newRow][newCol];
