   700→                        if (targetColor !== color) {
   701→                            moves.push({ row: newRow, col: newCol });
   702→                        }
   703→                    }
   704→                }
   705→            }
   706→
   707→            // Castling
   708→            if (!isInCheck(color)) {
   709→                const row = color === 'white' ? 7 : 0;
   710→
   711→                if (castlingRights[color].kingSide) {
   712→                    if (!board[row][5] && !board[row][6] &&
   713→                        !isSquareAttacked(row, 5, color) && !isSquareAttacked(row, 6, color)) {
   714→                        moves.push({ row: row, col: 6 });
   715→                    }
   716→                }
   717→
   718→                if (castlingRights[color].queenSide) {
   719→                    if (!board[row][1] && !board[row][2] && !board[row][3] &&
   720→                        !isSquareAttacked(row, 2, color) && !isSquareAttacked(row, 3, color)) {
   721→                        moves.push({ row: row, col: 2 });
   722→                    }
   723→                }
   724→            }
   725→
   726→            return moves;
