   729→        function isInBounds(row, col) {
   730→            return row >= 0 && row < 8 && col >= 0 && col < 8;
   731→        }
   732→
   733→        function isInCheck(color) {
   734→            // Find king position
   735→            let kingRow, kingCol;
   736→            const kingPiece = color === 'white' ? 'K' : 'k';
   737→
   738→            for (let row = 0; row < 8; row++) {
   739→                for (let col = 0; col < 8; col++) {
   740→                    if (board[row][col] === kingPiece) {
   741→                        kingRow = row;
   742→                        kingCol = col;
   743→                        break;
   744→                    }
   745→                }
   746→            }
   747→
   748→            return isSquareAttacked(kingRow, kingCol, color);
   749→        }
   750→
   751→        function isSquareAttacked(row, col, defendingColor) {
   752→            const attackingColor = defendingColor === 'white' ? 'black' : 'white';
   753→
   754→            for (let r = 0; r < 8; r++) {
   755→                for (let c = 0; c < 8; c++) {
   756→                    const piece = board[r][c];
   757→                    if (piece) {
   758→                        const pieceColor = piece === piece.toUpperCase() ? 'white' : 'black';
   759→                        if (pieceColor === attackingColor) {
   760→                            const attacks = getAttackSquares(r, c, pieceColor);
   761→                            if (attacks.some(a => a.row === row && a.col === col)) {
   762→                                return true;
   763→                            }
   764→                        }
   765→                    }
   766→                }
   767→            }
   768→
   769→            return false;
   770→        }
   771→
   772→        function getAttackSquares(row, col, color) {
   773→            const piece = board[row][col];
   774→            const pieceType = piece.toLowerCase();
   775→
   776→            switch (pieceType) {
   777→                case 'p':
   778→                    const direction = color === 'white' ? -1 : 1;
   779→                    return [
   780→                        { row: row + direction, col: col - 1 },
   781→                        { row: row + direction, col: col + 1 }
   782→                    ].filter(m => isInBounds(m.row, m.col));
   783→                case 'r':
   784→                    return getRookMoves(row, col, color);
   785→                case 'n':
   786→                    return getKnightMoves(row, col, color);
   787→                case 'b':
   788→                    return getBishopMoves(row, col, color);
   789→                case 'q':
   790→                    return getQueenMoves(row, col, color);
   791→                case 'k':
   792→                    const moves = [];
   793→                    const offsets = [
   794→                        [-1, -1], [-1, 0], [-1, 1],
   795→                        [0, -1],          [0, 1],
   796→                        [1, -1],  [1, 0], [1, 1]
   797→                    ];
   798→                    for (const [rowOffset, colOffset] of offsets) {
   799→                        const newRow = row + rowOffset;
   800→                        const newCol = col + colOffset;
   801→                        if (isInBounds(newRow, newCol)) {
   802→                            moves.push({ row: newRow, col: newCol });
   803→                        }
   804→                    }
   805→                    return moves;
   806→                default:
   807→                    return [];
   808→            }
   809→        }
