   811→        function wouldBeInCheck(fromRow, fromCol, toRow, toCol, color) {
   812→            // Make temporary move
   813→            const originalPiece = board[toRow][toCol];
   814→            const movingPiece = board[fromRow][fromCol];
   815→
   816→            board[toRow][toCol] = movingPiece;
   817→            board[fromRow][fromCol] = '';
   818→
   819→            const inCheck = isInCheck(color);
   820→
   821→            // Undo temporary move
   822→            board[fromRow][fromCol] = movingPiece;
   823→            board[toRow][toCol] = originalPiece;
   824→
   825→            return inCheck;
   826→        }
   827→
   828→        function isCheckmate(color) {
   829→            if (!isInCheck(color)) return false;
   830→
   831→            for (let row = 0; row < 8; row++) {
   832→                for (let col = 0; col < 8; col++) {
   833→                    const piece = board[row][col];
   834→                    if (piece) {
   835→                        const pieceColor = piece === piece.toUpperCase() ? 'white' : 'black';
   836→                        if (pieceColor === color) {
   837→                            const moves = getValidMoves(row, col);
   838→                            if (moves.length > 0) return false;
   839→                        }
   840→                    }
   841→                }
   842→            }
   843→
   844→            return true;
   845→        }
